import * as React from "react";
import { TagItem } from "../tags/tag";
import SearchSelect, { SearchItem, SearchSelectProps, SearchSelectState } from "./SearchSelect";

export interface SearchTagItem extends SearchItem {
  tags: TagItem[];
}

export interface SearchTagSelectProps extends SearchSelectProps {
  items: SearchTagItem[];
  selectedItem: SearchTagItem | null;
  onItemSelected: (i: SearchTagItem | null) => void;
}

export default class SearchTagSelect extends SearchSelect<SearchTagSelectProps> {
  filterItem = (item: SearchTagItem, searchInput: string) => {
    if (item.name.toLowerCase().includes(searchInput)) {
      return true;
    } else {
      let tagMatch = false;
      for (let tag of item.tags) {
        tagMatch = tagMatch || tag.name.toLowerCase().includes(searchInput);
      }
      return tagMatch;
    }
  };

  filterItems = (items: SearchTagItem[], searchInput: string) => {
    let filteredItems = items.filter((item) => this.filterItem(item, searchInput));
    return filteredItems;
  };

  getTagsHTML = (tags: TagItem[]) => {
    let tagElements = [];
    for (let tag of tags) {
      tagElements.push(
        <div key={tag.id} className="badge bg-primary rounded-pill">
          {tag.name}
        </div>
      );
    }
    return (
      <div className="d-flex flex-wrap gap-1 mt-1">
        {tagElements}
      </div>
    );
  };

  getItemHTML = (item: SearchTagItem) => {
    return (
      <div>
        <div>{item.name}</div>
        {this.getTagsHTML(item.tags)}
      </div>
    );
  };

  getItemsToShow = (items: SearchTagItem[]) => {
    let itemsToShow = [];
    const searchInputLower = this.state.searchInput.trim().toLowerCase();
    const sourceItems = Array.isArray(items) ? items : [];
    const filteredItems = searchInputLower ? this.filterItems(sourceItems, searchInputLower) : sourceItems;
    for (let i of filteredItems) {
      let id = i.id;
      itemsToShow.push(
        <li
          key={id}
          className="searchselect-item searchselect-item-tags"
          onMouseDown={(e) => e.preventDefault()}
          onClick={() => {
            this.props.onItemSelected(i);
            this.setState({ searchInput: i.name, isFocused: false });
          }}
        >
          {this.getItemHTML(i)}
        </li>
      );
    }
    return itemsToShow;
  };
}
