import * as React from "react";
import { useCallback, useEffect, useState } from "react";
import Login from "./login/Login";
import Main from "./main/Main";
import { saveTranslations } from "../../utils/Translator";
import { AUTH_EXPIRED_EVENT, ContentType, HttpVerb, sendHttpRequest } from "../../utils/httpRequest";
import api from "../api";

/* global localStorage */

enum Page {
  Main = "Main",
  Login = "Login",
}

const App: React.FC = () => {
  const [page, setPage] = useState<Page>(Page.Login);
  const [, setTranslationsVersion] = useState(0);

  const normalizeBaseUrl = (urlStr: string | null) => {
    if (!urlStr) return null;
    try {
      let tmpStr = urlStr;
      if (!tmpStr.startsWith("http://") && !tmpStr.startsWith("https://")) {
        tmpStr = "https://" + tmpStr;
      }
      const url = new URL(tmpStr);
      url.protocol = "https:";
      return url.origin;
    } catch {
      return null;
    }
  };

  /**
   * Load translations from Odoo using the token.
   */
  const getTranslations = async () => {
    try {
      const token = localStorage.getItem("odooConnectionToken");
      const authHeader = token?.startsWith("Bearer ") ? token : token ? `Bearer ${token}` : null;
      const request = sendHttpRequest(
        HttpVerb.POST,
        api.baseURL + api.getTranslations,
        ContentType.Json,
        authHeader,
        {},
        true
      );
      const response = JSON.parse(await request.promise);
      saveTranslations(response.result);
      // Trigger a re-render so _t() reads updated translations.
      setTranslationsVersion((v) => v + 1);
    } catch (error) {
      console.log("Error fetching translations: " + String(error));
    }
  };

  /**
   * Called when a user logs in successfully.
   * Stores the token and shows the main app screen.
   */
  const connect = (token: string) => {
    localStorage.setItem("odooConnectionToken", token);
    getTranslations();
    setPage(Page.Main);
  };

  /**
   * Called when the user logs out.
   * Clears the token and shows the login screen.
   */
  const disconnect = useCallback(() => {
    localStorage.removeItem("odooConnectionToken");
    localStorage.removeItem("translations");
    localStorage.removeItem("translationsTimestamp");
    setPage(Page.Login);
  }, []);

  useEffect(() => {
    const onAuthExpired = () => {
      disconnect();
    };
    if (typeof window !== "undefined") {
      window.addEventListener(AUTH_EXPIRED_EVENT, onAuthExpired);
    }
    return () => {
      if (typeof window !== "undefined") {
        window.removeEventListener(AUTH_EXPIRED_EVENT, onAuthExpired);
      }
    };
  }, [disconnect]);

  /**
   * On app load, check if we already have a token in storage.
   * If so, skip login screen and go straight to the main app.
   */
  useEffect(() => {
    const token = localStorage.getItem("odooConnectionToken");
    const baseURL = normalizeBaseUrl(localStorage.getItem("baseURL"));

    if (token && baseURL) {
      api.baseURL = baseURL;
      localStorage.setItem("baseURL", baseURL);
      setPage(Page.Main);
      getTranslations();
    } else {
      setPage(Page.Login);
    }
  }, []);

  const getPage = () => {
    return page === Page.Login ? <Login onLogin={connect} /> : <Main disconnect={disconnect} />;
  };

  return <div>{getPage()}</div>;
};

export default App;
