import * as React from "react";
import { _t } from "../../../utils/Translator";
import Case, { CaseItem } from "../case/Case";
import { MainPages } from "../main/Main";

interface OpenCasePageProps {
  selectedCase: CaseItem | null;
  onCaseSelected: (c: CaseItem | null) => void;
  onConfirm: () => void;
  returnPage?: MainPages;
  goToPage: (page: MainPages) => void;
}

const OpenCasePage: React.FC<OpenCasePageProps> = (props: OpenCasePageProps) => {
  const { selectedCase, onCaseSelected, onConfirm, returnPage, goToPage } = props;

  const getCancelButton = () => {
    return (
        <button
          title="Return"
          type="button"
          className="btn btn-default"
          onClick={() => goToPage(returnPage ?? MainPages.MainPage)}
        >
          <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
        </button>
      );
  };

  const getConfirmButton = () => {
    return (
      <button title="Confirm" type="button" className="btn btn-primary" onClick={onConfirm}>
        {_t("Confirm")}
      </button>
    );
  };

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{_t("Select case")}</span>
      </div>
      <Case selectedCase={selectedCase} onCaseSelected={onCaseSelected} />
      <div className="d-flex justify-content-end page-button-container">
        {selectedCase && <div>{getConfirmButton()}</div>}
      </div>
    </div>
  );
};

export default OpenCasePage;
