import React, { FC } from "react";
import { _t } from "../../../utils/Translator";
import SearchSelect from "../searchselect/SearchSelect";
import { TagItem } from "../tags/tag";
import Tags from "../tags/tags";
import { DocSnippetItem } from "./DocSnippet";
import api from "../../api";

export interface SaveDocSnippetProps {
  docSnippets: DocSnippetItem[];
  selectedDocSnippet: DocSnippetItem | null;
  onDocSnippetSelected: (p: DocSnippetItem | null) => void;
  saveNew: boolean;
  newDocSnippetName: string;
  setNewDocSnippetName: (n: string) => void;
}

const SaveDocSnippet: FC<SaveDocSnippetProps> = ({
  docSnippets,
  selectedDocSnippet,
  onDocSnippetSelected,
  saveNew,
  newDocSnippetName,
  setNewDocSnippetName,
}) => {
  const getDocSnippetButton = () => {
    if (selectedDocSnippet) {
      const url = `${api.baseURL}/web#id=${selectedDocSnippet.id}&model=document_automation.snippet&view_type=form`;
      return (
        <a href={url} target="_blank" rel="noreferrer">
          <i className="fa fa-external-link" aria-hidden="true"></i>
        </a>
      );
    } else {
      return null;
    }
  };

  return (
    <div>
      <div className="mt-2">
        {saveNew ? (
          <input
            className="name-input form-control"
            type="text"
            placeholder={_t("Describe document snippet")}
            value={newDocSnippetName}
            onChange={(e) => setNewDocSnippetName(e.target.value)}
          />
        ) : (
          <SearchSelect
            items={docSnippets}
            selectedItem={selectedDocSnippet}
            onItemSelected={onDocSnippetSelected}
            selectText={_t("Select document snippet")}
            searchText={_t("Search document snippet")}
          />
        )}
      </div>
    </div>
  );
};

export default SaveDocSnippet;
