import * as React from "react";
import { useState } from "react";
import api from "../../api";
import { _t } from "../../../utils/Translator";
import { MainPages } from "../main/Main";
import DocTemplate, { DocTemplateItem } from "../doc_template/DocTemplate";
import Error from "../error/Error";

interface GenerateDocumentPageProps {
  docTemplates: DocTemplateItem[];
  selectedDocTemplate: DocTemplateItem | null;
  onDocTemplateSelected: (t: DocTemplateItem | null) => void;
  getConnectionToken: () => string;
  goToPage: (page: MainPages) => void;
}

const GenerateDocumentPage: React.FC<GenerateDocumentPageProps> = (props: GenerateDocumentPageProps) => {
  const { docTemplates, selectedDocTemplate, onDocTemplateSelected, getConnectionToken, goToPage } = props;
  const [error, setError] = useState<string>("");

  const onGenerateDocument = async () => {
    if (!selectedDocTemplate?.id) {
      setError("Please select a document template.");
      return;
    }
    const url = `${api.baseURL}/web#id=${selectedDocTemplate.id}&model=document_automation.template&view_type=form`;
    window.open(url, "_blank", "noopener,noreferrer");
  };

  const getCancelButton = () => {
    return (
      <button title="Return" type="button" className="btn btn-default" onClick={() => goToPage(MainPages.MainPage)}>
        <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
      </button>
    );
  };

  const getGenerateDocumentButton = () => {
    return (
      <button title="Confirm" type="button" className="btn btn-primary" onClick={onGenerateDocument}>
        {_t("Confirm")}
      </button>
    );
  };

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{_t("Create document")}</span>
      </div> 
      <Error error={error} setError={setError} />
      <DocTemplate
        docTemplates={docTemplates}
        selectedDocTemplate={selectedDocTemplate}
        onDocTemplateSelected={onDocTemplateSelected}
      />
      <div className="d-flex justify-content-end page-button-container">
        {selectedDocTemplate && <div>{getGenerateDocumentButton()}</div>}
      </div>
    </div>
  );
};

export default GenerateDocumentPage;
