import * as React from "react";
import { sendHttpRequest, HttpVerb, ContentType } from "../../../utils/httpRequest";
import api from "../../api";
import { _t } from "../../../utils/Translator";
import { MainPages } from "../main/Main";
import { DocSnippetItem } from "../doc_snippet/DocSnippet";
import { extractDocument } from "../../../utils/wordUtils";
import SaveDocSnippet from "../doc_snippet/SaveDocSnippet";
import { useState } from "react";
import Error from "../error/Error";
import Progress from "../progress/Progress";

interface SaveSnippetPageProps {
  docSnippets: DocSnippetItem[];
  selectedDocSnippet: DocSnippetItem | null;
  onDocSnippetSelected: (t: DocSnippetItem | null) => void;
  onDocSnippetCreated: (t: DocSnippetItem) => void;
  getConnectionToken: () => string;
  goToPage: (page: MainPages) => void;
}

const SaveSnippetPage: React.FC<SaveSnippetPageProps> = (props: SaveSnippetPageProps) => {
  const { 
    docSnippets, 
    selectedDocSnippet, 
    onDocSnippetSelected, 
    onDocSnippetCreated,
    getConnectionToken, 
    goToPage 
  } = props;
  const [error, setError] = useState<string>("");
  const [processing, setProcessing] = useState<boolean>(false);
  const [saveNew, setSaveNew] = useState<boolean>(false);
  const [newDocSnippetName, setNewDocSnippetName] = useState<string>("");

  const saveDocSnippet = async (datas: string, snippet: DocSnippetItem | null) => {
    let response = null;
    try {
      const request = sendHttpRequest(
        HttpVerb.POST,
        api.baseURL + api.saveDocSnippet,
        ContentType.Json,
        getConnectionToken(),
        { datas: datas, snippet_id: snippet && snippet.id },
        true
      );
      response = JSON.parse(await request.promise);
    } catch (error) {
      setError(String(error));
    }
    return response;
  };

  const saveNewDocSnippet = async (datas: string, docSnippetName: string) => {
    let response = null;
    try {
      let request = sendHttpRequest(
        HttpVerb.POST,
        api.baseURL + api.saveNewDocSnippet,
        ContentType.Json,
        getConnectionToken(),
        { datas: datas, snippet_name: docSnippetName },
        true
      );
      response = JSON.parse(await request.promise);
    } catch (error) {
      setError(String(error));
    }
    return response;
  };

  const onSaveDocSnippet = async () => {
    setProcessing(true);
    const fileContent = await extractDocument();
    const datas = btoa(fileContent.toString());
    if (saveNew) {
        const response = await saveNewDocSnippet(datas, newDocSnippetName);
        if (response.result.success) {
          onDocSnippetCreated(response.result.data.snippet);
          onDocSnippetSelected(response.result.data.snippet);
          goToPage(MainPages.MainPage);
        } else {
          setError(response.result.error);
        }
    } else {
        const response = await saveDocSnippet(datas, selectedDocSnippet);
        if (response.result.success) {
          goToPage(MainPages.MainPage);
        } else {
          setError(response.result.error);
        }
    }
    setProcessing(false);
  };

  const getSaveDocSnippetButton = () => {
    return (
      <button title="Confirm" type="button" className="btn btn-primary" onClick={onSaveDocSnippet}>
        <span>{_t("Confirm")}</span>
      </button>
    );
  };

  const getCancelButton = () => {
    return (
      <button title="Return" type="button" className="btn btn-default" onClick={() => goToPage(MainPages.MainPage)}>
        <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
      </button>
    );
  };

  const getNewDocSnippetButton = () => {
    return (
      <button
        title="New"
        type="button"
        className="btn btn-light"
        onClick={() => setSaveNew(true)}
      >
        {_t("New")}
      </button>
    );
  };

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{_t("Save snippet")}</span>
      </div>
      <Error error={error} setError={setError} />
      <SaveDocSnippet
        docSnippets={docSnippets}
        selectedDocSnippet={selectedDocSnippet}
        onDocSnippetSelected={onDocSnippetSelected}
        saveNew={saveNew}
        newDocSnippetName={newDocSnippetName}
        setNewDocSnippetName={setNewDocSnippetName}
      />
      <div className="d-flex justify-content-end gap-2 page-button-container">
        {!saveNew && <span>{getNewDocSnippetButton()}</span>}
        {(selectedDocSnippet || (saveNew && newDocSnippetName.trim())) && (
          <span>{getSaveDocSnippetButton()}</span>
        )}
      </div>
      <Progress processing={processing} />
    </div>
  );
};

export default SaveSnippetPage;
