export const getSelectedText = () => {
  return new Promise<Office.AsyncResult<string>>((resolve) => {
    Office.context.document.getSelectedDataAsync(Office.CoercionType.Text, resolve);
  });
};

export const setSelectedText = (text: string) => {
  return new Promise<Office.AsyncResult<void>>((resolve) => {
    Office.context.document.setSelectedDataAsync(text, resolve);
  });
};

export const insertTextAfterSelection = (text: string) => {
  return Word.run(async (context) => {
    const range = context.document.getSelection();
    range.insertText(text, Word.InsertLocation.after);
    try {
      await context.sync();
    } catch (error) {
      console.log("Error while inserting after selection:");
      console.log(error);
    }
  });
};

export const appendText = (text: string) => {
  return Word.run(async (context) => {
    context.document.body.insertText(text, Word.InsertLocation.end);
    try {
      await context.sync();
    } catch (error) {
      console.log("Error while appending text:");
      console.log(error);
    }
  });
};

export const insertDocument = (datas: string) => {
  return Word.run(async (context) => {
    context.document.insertFileFromBase64(datas, Word.InsertLocation.replace, {
      importTheme: true,
      importStyles: true,
      importParagraphSpacing: true,
      importPageColor: true,
      importDifferentOddEvenPages: true,
    });
    try {
      await context.sync();
    } catch (error) {
      console.log("Error while insterting document:");
      console.log(error);
    }
  });
};

// The following example gets the document in Office Open XML ("compressed") format in 65536 bytes (64 KB) slices.
function getDocumentAsCompressed(callback: (fileContent: string) => void) {
  Office.context.document.getFileAsync(
    Office.FileType.Compressed,
    { sliceSize: 65536 /* 64 KB */ },
    (result) => {
      if (result.status === Office.AsyncResultStatus.Succeeded) {
        // If the getFileAsync call succeeded, then
        // result.value will return a valid File Object.
        const myFile = result.value;
        const sliceCount = myFile.sliceCount;
        const docDataSlices = [];
        let slicesReceived = 0;
        let gotAllSlices = true;

        // Get the file slices.
        getSliceAsync(myFile, 0, sliceCount, gotAllSlices, docDataSlices, slicesReceived, callback);
      } else {
        console.log("Error while getting document file:");
        console.log(result.error.message);
      }
    }
  );
}

function getSliceAsync(
  file: Office.File,
  nextSlice: number,
  sliceCount: number,
  gotAllSlices: boolean,
  docDataSlices: any[],
  slicesReceived: number,
  callback: (fileContent: string) => void
) {
  file.getSliceAsync(nextSlice, (sliceResult) => {
    if (sliceResult.status === Office.AsyncResultStatus.Succeeded) {
      if (!gotAllSlices) {
        /* Failed to get all slices, no need to continue. */
        return;
      }

      // Got one slice, store it in a temporary array.
      // (Or you can do something else, such as
      // send it to a third-party server.)
      docDataSlices[sliceResult.value.index] = sliceResult.value.data;
      if (++slicesReceived === sliceCount) {
        // All slices have been received.
        file.closeAsync();
        onGotAllSlices(docDataSlices, callback);
      } else {
        getSliceAsync(file, ++nextSlice, sliceCount, gotAllSlices, docDataSlices, slicesReceived, callback);
      }
    } else {
      gotAllSlices = false;
      file.closeAsync();
      console.log("getSliceAsync Error:");
      console.log(sliceResult.error.message);
    }
  });
}

function onGotAllSlices(docDataSlices: any[], callback: (fileContent: string) => void) {
  let docData = [];
  for (let i = 0; i < docDataSlices.length; i++) {
    docData = docData.concat(docDataSlices[i]);
  }

  let fileContent = "";
  for (let j = 0; j < docData.length; j++) {
    fileContent += String.fromCharCode(docData[j]);
  }

  // Now all the file content is stored in 'fileContent' variable,
  // you can do something with it, such as print, fax...
  callback(fileContent);
}

export const extractDocument: () => Promise<string> = () => {
  return new Promise((resolve) => {
    getDocumentAsCompressed(resolve);
  });
};
