import * as React from "react";
import { useState } from "react";
import { _t } from "../../../utils/Translator";
import Workflow, { WorkflowItem } from "../workflow/Workflow";
import { MainPages } from "../main/Main";
import Error from "../error/Error";

interface OpenWorkflowPageProps {
  workflows: WorkflowItem[];
  selectedWorkflow: WorkflowItem | null;
  onWorkflowSelected: (w: WorkflowItem | null) => void;
  onConfirm?: () => void;
  returnPage?: MainPages;
  goToPage: (page: MainPages) => void;
}

const OpenWorkflowPage: React.FC<OpenWorkflowPageProps> = (props: OpenWorkflowPageProps) => {
  const { workflows, selectedWorkflow, onWorkflowSelected, onConfirm, returnPage, goToPage } = props;
  const [error, setError] = useState<string>("");

  const onConfirmWorkflow = () => {
    if (!selectedWorkflow) {
      setError("Please select a workflow.");
      return;
    }
    if (onConfirm) {
      onConfirm();
    } else {
      goToPage(returnPage ?? MainPages.MainPage);
    }
  };

  const getConfirmButton = () => {
    return (
      <button title="Confirm" type="button" className="btn btn-primary" onClick={onConfirmWorkflow}>
        {_t("Confirm")}
      </button>
    );
  };

  const getCancelButton = () => {
    return (
      <button
        title="Return"
        type="button"
        className="btn btn-default"
        onClick={() => goToPage(returnPage ?? MainPages.MainPage)}
      >
        <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
      </button>
    );
  };

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{_t("Select workflow")}</span>
      </div>
      <Error error={error} setError={setError} />
      <Workflow
        workflows={workflows}
        selectedWorkflow={selectedWorkflow}
        onWorkflowSelected={onWorkflowSelected}
      />
      <div className="d-flex justify-content-between page-button-container">
        {selectedWorkflow && <div>{getConfirmButton()}</div>} 
      </div>
    </div>
  );
};

export default OpenWorkflowPage;
