import * as React from "react";
import { sendHttpRequest, HttpVerb, ContentType } from "../../../utils/httpRequest";
import api from "../../api";
import { _t } from "../../../utils/Translator";
import Document, { DocumentItem } from "../document/Document";
import { MainPages } from "../main/Main";
import { insertDocument } from "../../../utils/wordUtils";
import { TagItem } from "../tags/tag";
import Error from "../error/Error";
import { useState } from "react";

interface OpenDocumentPageProps {
  documents: DocumentItem[];
  selectedDocument: DocumentItem | null;
  onDocumentSelected: (d: DocumentItem | null) => void;
  documentTags: TagItem[];
  getConnectionToken: () => string;
  goToOpenCasePage: () => void;
  goToPage: (page: MainPages) => void;
}

const OpenDocumentPage: React.FC<OpenDocumentPageProps> = (props: OpenDocumentPageProps) => {
  const {
    selectedDocument,
    documents,
    onDocumentSelected,
    documentTags,
    getConnectionToken,
    goToOpenCasePage,
    goToPage,
  } = props;
  const [error, setError] = useState<string>("");

  const openDocument = async (document: DocumentItem | null) => {
    let response = null;
    try {
      const request = sendHttpRequest(
        HttpVerb.POST,
        api.baseURL + api.openDocument,
        ContentType.Json,
        getConnectionToken(),
        { document_id: document && document.id },
        true
      );
      response = JSON.parse(await request.promise);
    } catch (error) {
      setError(String(error));
    }
    return response;
  };

  const onOpenDocument = async () => {
    const response = await openDocument(selectedDocument);
    if (response.result.success) {
      await insertDocument(response.result.data.datas);
      goToPage(MainPages.MainPage);
    } else {
      setError(response.result.error);
    }
  };

  const getOpenDocumentButton = () => {
    return (
      <button title="Confirm" type="button" className="btn btn-primary" onClick={onOpenDocument}>
        {_t("Confirm")}
      </button>
    );
  };

  const getCancelButton = () => {
    return (
      <button
        title="Return"
        type="button"
        className="btn btn-default"
        onClick={goToOpenCasePage}
      >
        <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
      </button>
    );
  };

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{_t("Select document")}</span>
      </div>
      <Error error={error} setError={setError} />
      <Document
        documents={documents}
        selectedDocument={selectedDocument}
        onDocumentSelected={onDocumentSelected}
      />
      <div className="d-flex justify-content-end page-button-container">
        {selectedDocument && <div>{getOpenDocumentButton()}</div>}
      </div>
    </div>
  );
};

export default OpenDocumentPage;
