import React, { FC, useState } from "react";
import api from "../../api";
import { _t } from "../../../utils/Translator";
import { ContentType, HttpVerb, sendHttpRequest } from "../../../utils/httpRequest";
import LazySearchSelect from "../searchselect/LazySearchSelect";
import Error from "../error/Error";

export interface CaseItem {
  id: number;
  name: string;
  reference_number?: string;
}

export interface CaseProps {
  selectedCase: CaseItem | null;
  onCaseSelected: (c: CaseItem | null) => void;
}

/* global localStorage */
const getConnectionToken = () => "Bearer " + localStorage.getItem("odooConnectionToken");

const Case: FC<CaseProps> = ({ selectedCase, onCaseSelected }) => {
  const [cases, setCases] = useState<CaseItem[]>([]);
  const [error, setError] = useState<string>("");

  const searchCases = async (query: string) => {
    if (!query || query.trim().length < 2) return;
    let response = null;
    try {
      const request = sendHttpRequest(
        HttpVerb.POST,
        api.baseURL + api.lazySearchCases,
        ContentType.Json,
        getConnectionToken(),
        { query, limit: 10, offset: 0 },
        true
      );
      response = JSON.parse(await request.promise);
      if (response.result.success) {
        const rows = (response.result.data.cases as CaseItem[]).map(c => ({
          ...c,
          // make ref searchable/visible even if LazySearchSelect only uses .name
          name: c.name + (c.reference_number ? ` (#${c.reference_number})` : ""),
        }));
        setCases(rows);
      } else {
       setError(response.result.error);
      }
    } catch (err) {
      setError(String(err));
    }
    return response;
  };

  return (
    <div>
      <Error error={error} setError={setError} />
      <LazySearchSelect
        items={cases}
        selectedItem={selectedCase}
        onItemSelected={onCaseSelected}
        selectText={_t("Select case")}
        searchText={_t("Search case")}
        onSearch={searchCases}
      />
    </div>
  );
};

export default Case;
