import * as React from "react";
import { useEffect, useState } from "react";
import { ContentType, HttpVerb, sendHttpRequest } from "../../../utils/httpRequest";
import api from "../../api";
import type { CaseItem } from "../case/Case";
import type { DocumentItem } from "../document/Document";
import GenerateDocumentPage from "../pages/GenerateDocumentPage";
import MainPage from "../pages/MainPage";
import OpenDocumentPage from "../pages/OpenDocumentPage";
import OpenPage from "../pages/OpenPage";
import OpenTemplatePage from "../pages/OpenTemplatePage";
import OpenSnippetPage from "../pages/OpenSnippetPage";
import SaveDocumentPage from "../pages/SaveDocumentPage";
import SavePage from "../pages/SavePage";
import SaveTemplatePage from "../pages/SaveTemplatePage";
import SaveSnippetPage from "../pages/SaveSnippetPage";
import { TagItem } from "../tags/tag";
import { DocTemplateItem } from "../doc_template/DocTemplate";
import { DocSnippetItem } from "../doc_snippet/DocSnippet";
import { WorkflowItem } from "../workflow/Workflow";
import OpenAnalysisPage from "../pages/OpenAnalysisPage";
import AnalysisPage from "../pages/AnalysisPage";
import OpenWorkflowPage from "../pages/OpenWorkflowPage";
import OpenCasePage from "../pages/OpenCasePage";
import Header, { UserData } from "../header/Header";
import Footer from "../footer/Footer";
import ErrorBanner from "../error/Error";
import { AnalysisItem } from "../analysis/Analysis";

/* global localStorage */

const getConnectionToken = () => "Bearer " + localStorage.getItem("odooConnectionToken");
const ensureConnection = () => {
  const token = localStorage.getItem("odooConnectionToken");
  const baseURL = api.baseURL;
  if (!token || !baseURL) {
    return {
      ok: false,
      error: "Missing server URL or token. Please log in again.",
    } as const;
  }
  return { ok: true } as const;
};
const getErrorMessage = (error: unknown) => {
  if (error instanceof globalThis.Error) {
    if (error.message === "0") return "Network error. Please check your connection.";
    return error.message;
  }
  if (error === 0) return "Network error. Please check your connection.";
  return String(error);
};
const isNetworkError = (message: string) =>
  message.startsWith("Network error") || message.startsWith("0 Network error");

const postJson = async (
  endpoint: string,
  token: string,
  payload: Record<string, unknown> = {}
) => {
  const req = sendHttpRequest(HttpVerb.POST, endpoint, ContentType.Json, token, payload, true);
  return JSON.parse(await req.promise);
};

export enum MainPages {
  MainPage,
  OpenPage,
  SavePage,
  OpenDocumentPage,
  SaveDocumentPage,
  GenerateDocumentPage,
  OpenTemplatePage,
  SaveTemplatePage,
  OpenSnippetPage,
  SaveSnippetPage,
  OpenAnalysisPage,
  OpenCasePage,
  AnalysisPage,
  OpenWorkflowPage,
}

type MainProps = { disconnect: () => void };

const Main: React.FC<MainProps> = ({ disconnect }): JSX.Element => {
  const [error, setError] = useState<string>("");
  const [page, setPage] = useState<MainPages>(MainPages.MainPage);
  const [selectedCase, setSelectedCase] = useState<CaseItem | null>(null);
  const [documentsFromSelectedCase, setDocumentsFromSelectedCase] = useState<DocumentItem[]>([]);
  const [selectedDocument, setSelectedDocument] = useState<DocumentItem | null>(null);
  const [documentTags, setDocumentTags] = useState<TagItem[]>([]);
  const [userData, setUserData] = useState<UserData | null>(null);
  const [docTemplates, setDocTemplates] = useState<DocTemplateItem[]>([]);
  const [selectedDocTemplate, setSelectedDocTemplate] = useState<DocTemplateItem | null>(null);
  const [docSnippets, setDocSnippets] = useState<DocSnippetItem[]>([]);
  const [selectedDocSnippet, setSelectedDocSnippet] = useState<DocSnippetItem | null>(null);
  const [workflows, setWorkflows] = useState<WorkflowItem[]>([]);
  const [selectedWorkflow, setSelectedWorkflow] = useState<WorkflowItem | null>(null);
  const [selectedAnalysis, setSelectedAnalysis] = useState<AnalysisItem | null>(null);
  const [openCaseConfirmPage, setOpenCaseConfirmPage] = useState<MainPages>(MainPages.MainPage);
  const [openCaseReturnPage, setOpenCaseReturnPage] = useState<MainPages>(MainPages.MainPage);

  /* ========================== Helpers ========================== */

  // Load initial app data (tags, templates, user)
  const getData = async () => {
    try {
      const ready = ensureConnection();
      if (!ready.ok) {
        setError(ready.error);
        return null;
      }
      return await postJson(api.baseURL + api.getData, getConnectionToken());
    } catch (e) {
      setError(getErrorMessage(e));
      return null;
    }
  };

  // Load case documents data
  const getDocuments = async (caseId: number) => {
    try {
      const ready = ensureConnection();
      if (!ready.ok) {
        setError(ready.error);
        return null;
      }
      return await postJson(api.baseURL + api.getDocuments, getConnectionToken(), { case_id: caseId });
    } catch (e) {
      setError(getErrorMessage(e));
      return null;
    }
  };

  // Resolve latest opened document for this user
  const resolveRecentDocument = async (): Promise<{ case_id: number; document_id: number } | null> => {
    try {
      const ready = ensureConnection();
      if (!ready.ok) {
        setError(ready.error);
        return null;
      }
      const resp = await postJson(api.baseURL + api.resolveOpenedDocument, getConnectionToken());
      const root = resp?.result ?? resp;

      if (!root?.success) {
        if (root?.error && root.error !== 0) {
          setError(String(root.error));
        }
        return null;
      }
      const data = root?.data;
      if (!data?.case_id || !data?.document_id) {
        return null;
      }
      return { case_id: Number(data.case_id), document_id: Number(data.document_id) };
    } catch (e) {
      setError(getErrorMessage(e));
      return null;
    }
  };

  // Resolve latest opened template/snippet for this user.
  const resolveRecentDocItem = async (itemType: "template" | "snippet"): Promise<{ id: number } | null> => {
    try {
      const ready = ensureConnection();
      if (!ready.ok) {
        setError(ready.error);
        return null;
      }
      const resp = await postJson(api.baseURL + api.resolveOpenedDocItem, getConnectionToken(), {
        item_type: itemType,
      });
      const root = resp?.result ?? resp;

      if (!root?.success) {
        if (root?.error && root.error !== 0) {
          setError(String(root.error));
        }
        return null;
      }

      const raw = root?.data;
      const data = Array.isArray(raw) ? raw[0] : raw;
      if (!data) return null;

      const apiItemType = data.item_type || data.type || data.item;
      if (apiItemType && apiItemType !== itemType) {
        return null;
      }

      const id =
        data.id ??
        data.res_id ??
        data.item_id ??
        data.template_id ??
        data.snippet_id;
      if (!id) return null;

      return { id: Number(id) };
    } catch (e) {
      const msg = getErrorMessage(e);
      if (isNetworkError(msg)) {
        // Endpoint may be unavailable on some deployments; treat as non-fatal.
        console.warn(msg);
        return null;
      }
      setError(msg);
      return null;
    }
  };

  // Resolve latest opened template for this user.
  const resolveRecentTemplate = async (): Promise<{ id: number } | null> => {
    return resolveRecentDocItem("template");
  };

  // Resolve latest opened snippet for this user.
  const resolveRecentSnippet = async (): Promise<{ id: number } | null> => {
    return resolveRecentDocItem("snippet");
  };

  /* =========================== Effects ========================= */

  // Initial data
  useEffect(() => {
    getData().then((response) => {
      const root = response?.result ?? response;
      if (root?.data) {
        setDocumentTags(root.data.document_tags || []);
        setDocTemplates(root.data.doc_templates || []);
        setDocSnippets(root.data.doc_snippets || []);
        setWorkflows(root.data.workflows || []);
        setUserData(root.data.user);
        setPage(MainPages.MainPage);
      }
    });
  }, []);

  const refreshRecentDocument = async () => {
    const ids = await resolveRecentDocument();
    if (!ids) return; // nothing recent; user can select manually

    const resp = await getDocuments(ids.case_id);
    const root = resp?.result ?? resp;
    if (!root?.success || !root?.data) {
      setError(root?.error && root.error !== 0 ? String(root.error) : "Failed to load case.");
      return;
    }

    const data = root.data;
    const caseObjFromApi = (data.case as CaseItem | undefined) || undefined;
    const docs = normalizeDocuments(data.documents || []);

    // Ensure a case object with a readable name
    let caseItem: CaseItem;
    if (caseObjFromApi) {
      caseItem = caseObjFromApi;
    } else {
      const caseName =
        (data.case_name as string) ||
        (data.name as string) ||
        "";
      caseItem = { id: ids.case_id, name: caseName } as CaseItem;
    }

    setSelectedCase(caseItem);
    setDocumentsFromSelectedCase(docs || []);

    // Choose the real document object if present
    const found = docs.find((d) => Number(d.id) === Number(ids.document_id));
    if (found) {
      setSelectedDocument(found);
    } else {
      const stub = { id: ids.document_id, caseId: ids.case_id } as DocumentItem;
      setSelectedDocument(stub);
    }
  };

  const refreshRecentDocItem = async <T extends { id: number }>(
    items: T[],
    resolver: () => Promise<{ id: number } | null>,
    setter: React.Dispatch<React.SetStateAction<T | null>>,
    fallbackName: string
  ) => {
    if (!items || items.length === 0) return;
    const res = await resolver();
    if (!res) return;

    const found = items.find((t) => Number(t.id) === Number(res.id));
    if (found) {
      setter(found);
    } else {
      setter({ id: res.id, name: fallbackName } as unknown as T);
    }
  };

  const normalizeDocuments = (docs: any[]): DocumentItem[] => {
    const tagsById = new Map<number, TagItem>(
      (documentTags || []).map((t) => [Number(t.id), t])
    );
    return (docs || []).map((doc) => {
      const rawTags = Array.isArray(doc.tags) ? doc.tags : null;
      let tags: TagItem[] = [];
      if (rawTags) {
        tags = rawTags as TagItem[];
      } else if (Array.isArray(doc.tag_ids)) {
        const tagIds = doc.tag_ids;
        if (tagIds.length > 0 && Array.isArray(tagIds[0])) {
          tags = tagIds.map((t: any) => ({ id: Number(t[0]), name: String(t[1] ?? "") }));
        } else {
          tags = tagIds
            .map((id: any) => tagsById.get(Number(id)))
            .filter(Boolean) as TagItem[];
        }
      }
      return { ...(doc as DocumentItem), tags };
    });
  };

  // Auto-resolve case and document when entering main/open/save flows
  useEffect(() => {
    if (
      page === MainPages.MainPage ||
      page === MainPages.OpenDocumentPage ||
      page === MainPages.OpenCasePage ||
      page === MainPages.SavePage ||
      page === MainPages.SaveDocumentPage
    ) {
      refreshRecentDocument();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page]);

  // Auto-resolve templates/snippets on relevant page transitions
  useEffect(() => {
    if (
      page === MainPages.MainPage ||
      page === MainPages.OpenTemplatePage ||
      page === MainPages.SaveTemplatePage
    ) {
      refreshRecentTemplate();
    }
    if (
      page === MainPages.MainPage ||
      page === MainPages.OpenSnippetPage ||
      page === MainPages.SaveSnippetPage
    ) {
      refreshRecentSnippet();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page]);

  const refreshRecentTemplate = async () => {
    await refreshRecentDocItem(docTemplates, resolveRecentTemplate, setSelectedDocTemplate, "Template");
  };

  const refreshRecentSnippet = async () => {
    await refreshRecentDocItem(docSnippets, resolveRecentSnippet, setSelectedDocSnippet, "Snippet");
  };

  // Auto-resolve template/snippet when data arrives
  useEffect(() => {
    refreshRecentTemplate();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [docTemplates]);

  useEffect(() => {
    refreshRecentSnippet();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [docSnippets]);

  // Ensure document tags are filled once tags are loaded.
  useEffect(() => {
    if (!documentsFromSelectedCase || documentsFromSelectedCase.length === 0) return;
    setDocumentsFromSelectedCase(normalizeDocuments(documentsFromSelectedCase));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [documentTags]);

  // When a case is selected (manually or programmatically), load its documents
  useEffect(() => {
    if (!selectedCase?.id) return;
    getDocuments(selectedCase.id).then((resp) => {
      const root = resp?.result ?? resp;
      if (!root?.success) {
        setError(root?.error && root.error !== 0 ? String(root.error) : "Failed to load documents for case.");
        return;
      }
      setDocumentsFromSelectedCase(normalizeDocuments(root.data?.documents || []));
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedCase?.id]);

  // Clear selected document if user switches to a different case
  useEffect(() => {
    if (!selectedDocument) return;
    if (!selectedCase || selectedCase.id !== (selectedDocument as any).caseId) {
      setSelectedDocument(null);
    }
  }, [selectedCase, selectedDocument]);

  // Clear workflow only when analysis is closed
  useEffect(() => {
    if (!selectedAnalysis?.id) {
      setSelectedWorkflow(null);
    }
  }, [selectedAnalysis?.id]);


  /* =========================== Pages =========================== */

  const onDocumentCreated = (d: DocumentItem) => {
    setDocumentsFromSelectedCase((prev) => (prev || []).concat([d]));
  };
  
  const onDocTemplateCreated = (d: DocTemplateItem) => {
    setDocTemplates((prev) => (prev || []).concat([d]));
  };

  const onDocSnippetCreated = (d: DocSnippetItem) => {
    setDocSnippets((prev) => (prev || []).concat([d]));
  };

  const goToOpenCase = (confirmPage: MainPages, returnPage: MainPages) => {
    setOpenCaseConfirmPage(confirmPage);
    setOpenCaseReturnPage(returnPage);
    setPage(MainPages.OpenCasePage);
  };

  const goToOpenDocument = () => {
    if (selectedCase?.id) {
      setPage(MainPages.OpenDocumentPage);
      return;
    }
    goToOpenCase(MainPages.OpenDocumentPage, MainPages.MainPage);
  };

  const goToOpenAnalysis = () => {
    setPage(MainPages.OpenAnalysisPage);
  };

  const goToSaveDocument = () => {
    if (selectedCase?.id) {
      setPage(MainPages.SaveDocumentPage);
      return;
    }
    goToOpenCase(MainPages.SaveDocumentPage, MainPages.MainPage);
  };

  const goToOpenCaseFromSaveDocument = () => {
    goToOpenCase(MainPages.SaveDocumentPage, MainPages.MainPage);
  };

  const goToOpenCaseFromOpenDocument = () => {
    goToOpenCase(MainPages.OpenDocumentPage, MainPages.MainPage);
  };

  const goToOpenCaseFromAnalysis = () => {
    goToOpenCase(MainPages.AnalysisPage, MainPages.AnalysisPage);
  };

  const mainPage = (
    <MainPage
      goToPage={setPage}
      userData={userData as UserData}
      onOpenAnalysis={goToOpenAnalysis}
    />
  );

  const openPage = <OpenPage onOpenDocument={goToOpenDocument} goToPage={setPage} />;

  const savePage = <SavePage onSaveDocument={goToSaveDocument} goToPage={setPage} />;

  const openDocumentPage = (
    <OpenDocumentPage
      documents={documentsFromSelectedCase}
      selectedDocument={selectedDocument}
      documentTags={documentTags}
      onDocumentSelected={setSelectedDocument}
      getConnectionToken={getConnectionToken}
      goToOpenCasePage={goToOpenCaseFromOpenDocument}
      goToPage={setPage}
    />
  );

  const saveDocumentPage = (
    <SaveDocumentPage
      selectedCase={selectedCase}
      documents={documentsFromSelectedCase}
      selectedDocument={selectedDocument}
      onDocumentSelected={setSelectedDocument}
      documentTags={documentTags}
      onDocumentCreated={onDocumentCreated}
      getConnectionToken={getConnectionToken}
      goToOpenCasePage={goToOpenCaseFromSaveDocument}
      goToPage={setPage}
    />
  );

  const generateDocumentPage = (
    <GenerateDocumentPage
      docTemplates={docTemplates}
      selectedDocTemplate={selectedDocTemplate}
      onDocTemplateSelected={setSelectedDocTemplate}
      getConnectionToken={getConnectionToken}
      goToPage={setPage}
    />
  );

  const openTemplatePage = (
    <OpenTemplatePage
      docTemplates={docTemplates}
      selectedDocTemplate={selectedDocTemplate}
      onDocTemplateSelected={setSelectedDocTemplate}
      getConnectionToken={getConnectionToken}
      goToPage={setPage}
    />
  );

  const openSnippetPage = (
    <OpenSnippetPage
      docSnippets={docSnippets}
      selectedDocSnippet={selectedDocSnippet}
      onDocSnippetSelected={setSelectedDocSnippet}
      getConnectionToken={getConnectionToken}
      goToPage={setPage}
    />
  );

  const saveTemplatePage = (
    <SaveTemplatePage
      docTemplates={docTemplates}
      selectedDocTemplate={selectedDocTemplate}
      onDocTemplateSelected={setSelectedDocTemplate}
      onDocTemplateCreated={onDocTemplateCreated}
      getConnectionToken={getConnectionToken}
      goToPage={setPage}
    />
  );

  const saveSnippetPage = (
    <SaveSnippetPage
      docSnippets={docSnippets}
      selectedDocSnippet={selectedDocSnippet}
      onDocSnippetSelected={setSelectedDocSnippet}
      onDocSnippetCreated={onDocSnippetCreated}
      getConnectionToken={getConnectionToken}
      goToPage={setPage}
    />
  );

  const openAnalysisPage = (
    <OpenAnalysisPage
      selectedCase={selectedCase}
      selectedAnalysis={selectedAnalysis}
      onCaseSelected={setSelectedCase}
      onAnalysisSelected={setSelectedAnalysis}
      workflows={workflows}
      goToPage={setPage}
    />
  );

  const openCasePage = (
    <OpenCasePage
      selectedCase={selectedCase}
      onCaseSelected={setSelectedCase}
      onConfirm={() => setPage(openCaseConfirmPage)}
      returnPage={openCaseReturnPage}
      goToPage={setPage}
    />
  );

  const analysisPage = (
    <AnalysisPage
      getConnectionToken={getConnectionToken}
      selectedCase={selectedCase}
      selectedAnalysis={selectedAnalysis}
      onAnalysisSelected={setSelectedAnalysis}
      onCaseSelected={setSelectedCase}
      selectedWorkflow={selectedWorkflow}
      onWorkflowSelected={setSelectedWorkflow}
      goToPage={setPage}
      goToOpenCasePage={goToOpenCaseFromAnalysis}
    />
  );

  const openWorkflowPage = (
    <OpenWorkflowPage
      workflows={workflows}
      selectedWorkflow={selectedWorkflow}
      onWorkflowSelected={setSelectedWorkflow}
      returnPage={MainPages.AnalysisPage}
      onConfirm={() => setPage(MainPages.AnalysisPage)}
      goToPage={setPage}
    />
  );

  const wrapPage = (pageEl: React.ReactNode) => (
    <>
      <Header userData={userData as UserData} />
      <div className="page">
        <ErrorBanner error={error} setError={setError} />
        {pageEl}
      </div>
      <Footer disconnect={disconnect} />
    </>
  );

  const pages: Partial<Record<MainPages, React.ReactNode>> = {
    [MainPages.MainPage]: mainPage,
    [MainPages.OpenPage]: openPage,
    [MainPages.SavePage]: savePage,
    [MainPages.OpenDocumentPage]: openDocumentPage,
    [MainPages.SaveDocumentPage]: saveDocumentPage,
    [MainPages.GenerateDocumentPage]: generateDocumentPage,
    [MainPages.OpenTemplatePage]: openTemplatePage,
    [MainPages.SaveTemplatePage]: saveTemplatePage,
    [MainPages.OpenSnippetPage]: openSnippetPage,
    [MainPages.SaveSnippetPage]: saveSnippetPage,
    [MainPages.OpenAnalysisPage]: openAnalysisPage,
    [MainPages.OpenCasePage]: openCasePage,
    [MainPages.AnalysisPage]: analysisPage,
    [MainPages.OpenWorkflowPage]: openWorkflowPage,
  };

  return wrapPage(pages[page] ?? mainPage);
};

export default Main;
