import * as React from "react";
import { useEffect, useState } from "react";
import { sendHttpRequest, HttpVerb, ContentType } from "../../../utils/httpRequest";
import api from "../../api";
import { _t } from "../../../utils/Translator";
import { MainPages } from "../main/Main";
import { getSelectedText, insertTextAfterSelection, setSelectedText } from "../../../utils/wordUtils";
import { CaseItem } from "../case/Case";
import type { AnalysisItem } from "../analysis/Analysis";
import Error from "../error/Error";
import Progress from "../progress/Progress";
import type { WorkflowItem } from "../workflow/Workflow";

enum MessageRole {
  System = "system",
  Assistant = "assistant",
  User = "user",
}

interface Message {
  role: MessageRole;
  content: string;
}

const sanitizeHtml = (html: string) => {
  if (!html) {
    return "";
  }
  const parser = new DOMParser();
  const doc = parser.parseFromString(html, "text/html");
  const blockedTags = ["script", "style", "iframe", "object", "embed", "link", "meta"];

  blockedTags.forEach((tag) => {
    doc.querySelectorAll(tag).forEach((node) => node.remove());
  });

  doc.querySelectorAll("*").forEach((el) => {
    Array.from(el.attributes).forEach((attr) => {
      const name = attr.name.toLowerCase();
      const value = attr.value;
      if (name.startsWith("on")) {
        el.removeAttribute(attr.name);
      }
      if ((name === "href" || name === "src") && /^\s*javascript:/i.test(value)) {
        el.removeAttribute(attr.name);
      }
    });
  });

  return doc.body.innerHTML;
};

const stripHtml = (html: string) => {
  if (!html) {
    return "";
  }
  const parser = new DOMParser();
  const doc = parser.parseFromString(html, "text/html");
  return doc.body.textContent ?? "";
};

const trimMiddle = (text: string, maxLength: number) => {
  if (!text) return '""';
  if (text.length <= maxLength) return `"${text}"`;
  const ellipsis = " [...] ";
  if (maxLength <= ellipsis.length) return `"[...]"`;
  const remaining = maxLength - ellipsis.length;
  const startLen = Math.ceil(remaining / 2);
  const endLen = Math.floor(remaining / 2);
  return `"${text.slice(0, startLen)}${ellipsis}${text.slice(text.length - endLen)}"`;
};

interface AnalysisPageProps {
  getConnectionToken: () => string;
  selectedAnalysis: AnalysisItem | null;
  onAnalysisSelected: (a: AnalysisItem | null) => void;
  selectedCase: CaseItem | null;
  onCaseSelected: (c: CaseItem | null) => void;
  selectedWorkflow: WorkflowItem | null;
  onWorkflowSelected: (w: WorkflowItem | null) => void;
  goToPage: (page: MainPages) => void;
  goToOpenCasePage: () => void;
}

type AnalysisPayload = {
  message?: string;
  messages?: Message[];
  workflow_step_name?: string;
  case_id?: number | string;
  case_name?: string;
  case_reference_number?: number | string;
  workflow_id?: number | string;
  workflow_name?: string;
  id?: number | string;
  name?: string;
};

const AnalysisPage: React.FC<AnalysisPageProps> = (props: AnalysisPageProps) => {
  const {
    getConnectionToken,
    selectedAnalysis,
    onAnalysisSelected,
    selectedCase,
    onCaseSelected,
    selectedWorkflow,
    onWorkflowSelected,
    goToPage,
    goToOpenCasePage,
  } = props;
  const [error, setError] = useState<string>("");
  const [processing, setProcessing] = useState<boolean>(false);
  const [selection, setSelection] = useState<string>("");
  const [message, setMessage] = useState<string>("");
  const [messages, setMessages] = useState<Message[]>([]);
  const [workflowStepName, setWorkflowStepName] = useState<string>("");

  const resolveCaseFromData = (data: Record<string, unknown> | undefined | null) => {
    if (!data) return null;
    const id =
      (data.case_id as number | string | undefined);
    const name =
      (data.case_name as string | undefined);
    const referenceNumber =
      (data.case_reference_number as string | number | undefined);
    if (!id || !name) return null;
    return {
      id: Number(id),
      name,
      reference_number:
        referenceNumber !== undefined && referenceNumber !== null
          ? String(referenceNumber)
          : undefined,
    } as CaseItem;
  };

  const resolveWorkflowFromData = (data: Record<string, unknown> | undefined | null) => {
    if (!data) return null;
    const id =
      (data.workflow_id as number | string | undefined);
    const name =
      (data.workflow_name as string | undefined);
    if (!id || !name) return null;
    return { id: Number(id), name } as WorkflowItem;
  };

  const postJson = async (endpoint: string, payload: Record<string, unknown>) => {
    const request = sendHttpRequest(
      HttpVerb.POST,
      api.baseURL + endpoint,
      ContentType.Json,
      getConnectionToken(),
      payload,
      true
    );
    try {
      const response = JSON.parse(await request.promise);
      return response?.result ?? response;
    } catch (error) {
      setError(String(error));
      return null;
    }
  };

  const setFields = (data: AnalysisPayload) => {
    setMessage(typeof data?.message === "string" ? data.message : "");
    setMessages((data?.messages || []).filter((m) => m?.content?.trim()));
    setWorkflowStepName(typeof data?.workflow_step_name === "string" ? data.workflow_step_name : "");
    const resolvedCase = resolveCaseFromData(data);
    if (resolvedCase && (!selectedCase?.id || selectedCase.id === resolvedCase.id)) {
      onCaseSelected(resolvedCase);
    }
    const resolvedWorkflow = resolveWorkflowFromData(data);
    if (resolvedWorkflow) {
      onWorkflowSelected(resolvedWorkflow);
    }
  };

  useEffect(() => {
    const run = async () => {
      if (!selectedAnalysis?.id) {
        return;
      }
      setProcessing(true);
      try {
        const root = await openAnalysis(selectedAnalysis);
        if (root?.success && root?.data) {
          setFields(root.data);
        } else {
          setError(
            root?.error && root.error !== 0
              ? String(root.error)
              : "Failed to open analysis."
          );
        }
      } finally {
        setProcessing(false);
      }
    };

    run();
    // Intentionally run only once when the page mounts.
    // selectedAnalysis is expected to be stable while this page is active.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (!Office?.context?.document?.addHandlerAsync) {
      return () => {};
    }

    const handler = () => {
      checkSelection();
    };

    Office.context.document.addHandlerAsync(
      Office.EventType.DocumentSelectionChanged,
      handler
    );

    checkSelection();

    return () => {
      Office.context.document.removeHandlerAsync(
        Office.EventType.DocumentSelectionChanged,
        { handler }
      );
    };
  }, []);

  
  const openAnalysis = async (analysis: AnalysisItem) => {
    return postJson(api.openAnalysis, { analysis_id: analysis && analysis.id });
  };

  const getResponse = async (
    message: string,
    analysisId: number | null,
    caseId: number | null
  ) => {
    return postJson(api.sendMessage, { message: message, analysis_id: analysisId, case_id: caseId });
  };

  const getNextWorkflowStep = async (
    analysisId: number | null,
    workflowId: number | null
  ) => {
    return postJson(api.nextWorkflowStep, {
      analysis_id: analysisId,
      workflow_id: workflowId,
    });
  };

  const resetWorkflow = async (
    analysisId: number) => {
    return postJson(api.resetWorkflow, { analysis_id: analysisId });
  };

  const resetCase = async (
    analysisId: number) => {
    return postJson(api.resetCase, { analysis_id: analysisId });
  };

  const onSendMessage = async () => {
    setProcessing(true);
    checkSelection();

    try {
      const baseMessage = typeof message === "string" ? message : "";
      let messageWithSelectedText = baseMessage;
      if (selection) {
        messageWithSelectedText = `${baseMessage}\n\nSelected text:\n\n${selection}`;
      }

      const response = await getResponse(
        messageWithSelectedText,
        selectedAnalysis?.id ?? null,
        selectedCase?.id ?? selectedAnalysis?.caseId ?? null
      );

      if (!response?.success) {
        setError(response?.error);
        return;
      }

      const analysisId = Number(
        response?.data?.id ?? selectedAnalysis?.id
      );
      if (!analysisId) {
        setError("Failed to resolve analysis after sending the message.");
        return;
      }

      if (response?.data) {
        const nextAnalysisId = Number(response.data?.id ?? selectedAnalysis?.id);
        if (nextAnalysisId) {
          onAnalysisSelected({
            id: nextAnalysisId,
            name: response.data?.name ?? selectedAnalysis?.name,
            caseId: response.data?.case_id ?? selectedAnalysis?.caseId,
          } as AnalysisItem);
        }
        setFields(response.data);
      } else {
        onAnalysisSelected({ id: analysisId } as AnalysisItem);
        setError(
          response?.error && response.error !== 0
            ? String(response.error)
            : "Failed to update analysis after sending the message."
        );
      }
      setMessage("");
    } finally {
      setProcessing(false);
    }
  };

  const onNextWorkflowStep = async () => {
    setProcessing(true);

    const analysisId = selectedAnalysis?.id ?? null;
    if (!selectedWorkflow?.id) {
      setError("Please select a workflow first.");
      setProcessing(false);
      return;
    }
 
    try {
      const response = await getNextWorkflowStep(analysisId, selectedWorkflow?.id ?? null);

      if (!response?.success) {
        setError(response?.error);
        return;
      }

      if (response?.data) {
        const nextAnalysisId = Number(response.data?.id ?? analysisId);
        if (nextAnalysisId) {
          onAnalysisSelected({
            id: nextAnalysisId,
            name: response.data?.name ?? selectedAnalysis?.name,
            caseId: response.data?.case_id ?? selectedAnalysis?.caseId,
          } as AnalysisItem);
        }
        setFields(response.data);
      } else {
        onAnalysisSelected({ id: analysisId } as AnalysisItem);
        setError(
          response?.error && response.error !== 0
            ? String(response.error)
            : "Failed to update analysis after next workflow step."
        );
      }
    } finally {
      setProcessing(false);
    }
  };

  const onResetWorkflow = async () => {
    setProcessing(true);
    onWorkflowSelected(null);

    const analysisId = selectedAnalysis?.id;
    if (!analysisId) {
      setProcessing(false);
      return;
    }

    try {
      const response = await resetWorkflow(analysisId);

      if (!response?.success) {
        setError(response?.error);
        return;
      }

      if (response?.data) {
        setFields(response.data);
      } else {
        onAnalysisSelected({ id: analysisId } as AnalysisItem);
        setError(
          response?.error && response.error !== 0
            ? String(response.error)
            : "Failed to update analysis after workflow reset."
        );
      }
    } finally {
      setProcessing(false);
    }
  };

  const onResetCase = async () => {
    setProcessing(true);
    onCaseSelected(null);

    const analysisId = selectedAnalysis?.id;
    if (!analysisId) {
      setProcessing(false);
      return;
    }

    try {
      const response = await resetCase(analysisId);

      if (!response?.success) {
        setError(response?.error);
        return;
      }

      if (response?.data) {
        setFields(response.data);
      } else {
        onAnalysisSelected({ id: analysisId } as AnalysisItem);
        setError(
          response?.error && response.error !== 0
            ? String(response.error)
            : "Failed to update analysis after case reset."
        );
      }
    } finally {
      setProcessing(false);
    }
  };

  const onLoadWorkflow = () => {
    goToPage(MainPages.OpenWorkflowPage);
  };

  const checkSelection = async () => {
    const selectedTextResponse = await getSelectedText();
    let selectedText: string;
    if (selectedTextResponse.status == Office.AsyncResultStatus.Succeeded) {
      selectedText = selectedTextResponse.value;
      setSelection(selectedText);
    } else {
      setError(selectedTextResponse.error.message);
    }
  };

  const onInsertText = async (text: string) => {
    const selectedTextResponse = await getSelectedText();
    if (selectedTextResponse.status == Office.AsyncResultStatus.Succeeded) {
      const selectedText = selectedTextResponse.value || "";
      const cleanText = stripHtml(text);
      if (selectedText.length > 0) {
        await insertTextAfterSelection(cleanText);
      } else {
        const response = await setSelectedText(cleanText);
        if (response.status == Office.AsyncResultStatus.Failed) {
          setError(response.error.message);
        }
      }
    } else {
      setError(selectedTextResponse.error.message);
    }
  };

  const onReplaceText = async (text: string) => {
    const response = await setSelectedText(stripHtml(text));
    if (response.status == Office.AsyncResultStatus.Failed) {
      setError(response.error.message);
    }
  };

  const getInsertTextButton = (text: string) => {
    return (
      <div role="button" className="btn btn-outline-primary btn-sm" onClick={() => onInsertText(text)}>
        <i className="fa fa-plus me-2" aria-hidden="true"></i>
        {_t("Insert")}
      </div>
    );
  };

  const getReplaceTextButton = (text: string) => {
    return (
      <div role="button" className="btn btn-outline-primary btn-sm" onClick={() => onReplaceText(text)}>
        <i className="fa fa-exchange me-2" aria-hidden="true"></i>
        {_t("Replace")}
      </div>
    );
  };

  const getSendButton = () => {
    return (
      <button type="button" className="btn btn-sm btn-primary" onClick={onSendMessage}>
        <span>{_t("Send")}</span>
      </button>
    );
  };

  const getAnalysisButton = () => {
    if (!selectedAnalysis?.id) {
      return null;
    }
    const url = `${api.baseURL}/web#id=${selectedAnalysis.id}&model=legal_intelligence.analysis&view_type=form`;
    return (
      <a
        href={url}
        target="_blank"
        rel="noreferrer"
        title="Open analysis"
        className="btn btn-default"
      >
        <i className="fa fa-external-link text-primary" aria-hidden="true"></i>
      </a>
    );
  };

  const getCancelButton = () => {
    return (
      <button
        title="Return"
        type="button"
        className="btn btn-default"
        onClick={() => {
          goToPage(MainPages.MainPage);
        }}
      >
        <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
      </button>
    );
  };

  const contextArea = (
    <div className="analysis-context mb-3">
      {selectedCase && (
        <div className="analysis-case">
          <div className="d-flex align-items-center gap-2">
            <span className="text-muted small">{selectedCase.name}</span>
            <i
              className="fa fa-times text-muted small"
              title="Reset case"
              onClick={onResetCase}
              role="button"
              aria-hidden="true"
            ></i>
          </div>
        </div>
      )}
      {selectedWorkflow && (
        <div className="analysis-workflow">
          <div className="d-flex align-items-center gap-2">
            <span className="text-muted small">{selectedWorkflow.name}</span>
            <i
              className="fa fa-times text-muted small"
              title="Reset workflow"
              onClick={onResetWorkflow}
              role="button"
              aria-hidden="true"
            ></i>
          </div>
          {workflowStepName && (
            <div className="d-flex align-items-center gap-2">
              <span className="text-muted small">{workflowStepName}</span>
            </div>
          )}
        </div>
      )}
      {selection && (
        <div className="analysis-selection">
          <div className="text-muted small">{trimMiddle(selection, 50)}</div>
        </div>
      )}
    </div>
  );

  const promptArea = (
    <div className="analysis-prompt bg-light">
      {contextArea}
      <div>
        <textarea
          className="form-control analysis-prompt-input"
          rows={5}
          placeholder={_t("Type a prompt...")}
          value={message}
          onClick={() => checkSelection()}
          onChange={(e) => setMessage(e.target.value)}
        />
      </div>
      <div className="btn-toolbar justify-content-between mt-3" role="toolbar">
        <div className="btn-group" role="group">
          {!selectedCase?.id && (
            <button title="Select case" className="btn btn-default" onClick={goToOpenCasePage} type="button">
              <i className="fa fa-folder-open-o text-primary" aria-hidden="true"></i>
            </button>
          )}
          {!selectedWorkflow ? (
            <button title="Load workflow" className="btn btn-default" onClick={onLoadWorkflow} type="button">
              <i className="fa fa-list-ol text-primary"></i>
            </button>
          ) : (
            !message && (
              <button title="Next step" className="btn btn-default" onClick={onNextWorkflowStep} type="button">
                <i className="fa fa-step-forward text-primary"></i>
              </button>
            )
          )}
          {getAnalysisButton()}
        </div>
        <span>{getSendButton()}</span>
      </div>
    </div>
  );

  const chatArea = (
    <>
      {messages.map(function (message, index) {
          const safeHtml = sanitizeHtml(message.content);
          if (message.role == "user") {
            return (
              <div key={`${message.role}-${index}`}>
                <div className="alert alert-success mt-3 mb-3" role="alert">
                  <div dangerouslySetInnerHTML={{ __html: safeHtml }}></div>
                </div>
              </div>
            );
          } else if (message.role == "assistant") {
            return (
              <div key={`${message.role}-${index}`}>
                <div className="alert alert-primary mt-3 mb-3" role="alert">
                  <div dangerouslySetInnerHTML={{ __html: safeHtml }}></div>
                  <div className="d-flex gap-2 mt-3">
                    {getInsertTextButton(message.content)}
                    {getReplaceTextButton(message.content)}
                  </div>
                </div>
              </div>
            );
          } else if (message.role == "system") {
            return (
              <div key={`${message.role}-${index}`}>
                <div className="alert alert-primary mt-3 mb-3" role="alert">
                  <div dangerouslySetInnerHTML={{ __html: safeHtml }}></div>
                </div>
              </div>
            );
          } else {
            return false;
          }
        })}
    </>
  );

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{selectedAnalysis?.name || _t("Analysis")}</span>
      </div>
      <Error error={error} setError={setError} />
      {promptArea}
      {chatArea}
      <Progress processing={processing} />
    </div>
  );
};

export default AnalysisPage;
