import * as React from "react";
import { _t } from "../../../utils/Translator";
import SearchSelect from "../searchselect/SearchSelect";

export interface DocTemplateItem {
  name: string;
  id: number;
  modelId: number;
}

export interface DocTemplateProps {
  docTemplates: DocTemplateItem[];
  selectedDocTemplate: DocTemplateItem | null;
  onDocTemplateSelected: (t: DocTemplateItem | null) => void;
}

const DocTemplate: React.FC<DocTemplateProps> = (props: DocTemplateProps) => {
  const { docTemplates, selectedDocTemplate, onDocTemplateSelected } = props;

  return (
    <div>
      <SearchSelect
        items={docTemplates}
        selectedItem={selectedDocTemplate}
        onItemSelected={onDocTemplateSelected}
        selectText={_t("Select document template")}
        searchText={_t("Search document template")}
      />
    </div>
  );
};

export default DocTemplate;
