import React, { FC, useEffect, useState } from "react";
import { _t } from "../../../utils/Translator";
import api from "../../api";
import { ContentType, HttpVerb, sendHttpRequest } from "../../../utils/httpRequest";
import LazySearchSelect from "../searchselect/LazySearchSelect";
import Error from "../error/Error";

export interface AnalysisItem {
  name: string;
  id: number;
  caseId: number;
}

export interface AnalysisProps {
  selectedAnalysis: AnalysisItem | null;
  onAnalysisSelected: (p: AnalysisItem | null) => void;
  selectedCaseId?: number | null;
}

/* global localStorage */
const getConnectionToken = () => "Bearer " + localStorage.getItem("odooConnectionToken");

const Analysis: FC<AnalysisProps> = ({ selectedAnalysis, onAnalysisSelected, selectedCaseId }) => {
  const [analyses, setAnalyses] = useState<AnalysisItem[]>([]);
  const [error, setError] = useState<string>("");

  useEffect(() => {
    setAnalyses([]);
  }, [selectedCaseId]);

  const searchAnalyses = async (query: string) => {
    if (!query || query.trim().length < 2) return;
    let response = null;
    try {
      const payload: { query: string; limit: number; offset: number; case_id?: number } = {
        query,
        limit: 10,
        offset: 0,
      };
      if (selectedCaseId) {
        payload.case_id = selectedCaseId;
      }

      const request = sendHttpRequest(
        HttpVerb.POST,
        api.baseURL + api.lazySearchAnalyses,
        ContentType.Json,
        getConnectionToken(),
        payload,
        true
      );
      response = JSON.parse(await request.promise);
      if (response.result.success) {
        const items = (response.result.data.analyses || []) as AnalysisItem[];
        setAnalyses(items);
      } else {
        setError(response.result.error);
      }
    } catch (err) {
      setError(String(err));
    }
    return response;
  };

  return (
    <div>
      <Error error={error} setError={setError} />
      <LazySearchSelect
        items={analyses}
        selectedItem={selectedAnalysis}
        onItemSelected={onAnalysisSelected}
        selectText={_t("Select analysis")}
        searchText={_t("Search analysis")}
        onSearch={searchAnalyses}
      />
    </div>
  );
};

export default Analysis;
