import React, { FC } from "react";
import { _t } from "../../../utils/Translator";
import SearchTagSelect from "../searchselect/SearchTagSelect";
import { TagItem } from "../tags/tag";
import Tags from "../tags/tags";
import { DocumentItem } from "./Document";
import api from "../../api";

export interface SaveDocumentProps {
  documents: DocumentItem[];
  selectedDocument: DocumentItem | null;
  onDocumentSelected: (p: DocumentItem | null) => void;
  saveNew: boolean;
  newDocumentName: string;
  setNewDocumentName: (n: string) => void;
  documentTags: TagItem[];
  selectedDocumentTags: TagItem[];
  onDocumentTagSelected: (t: TagItem) => void;
  onDocumentTagDeselected: (t: TagItem) => void;
}

const SaveDocument: FC<SaveDocumentProps> = ({
  documents,
  selectedDocument,
  onDocumentSelected,
  saveNew,
  newDocumentName,
  setNewDocumentName,
  documentTags,
  selectedDocumentTags,
  onDocumentTagSelected,
  onDocumentTagDeselected,
}) => {

  return (
    <div>
      <div className="mt-2">
        {saveNew ? (
          <input
            className="name-input form-control"
            type="text"
            placeholder={_t("Describe document")}
            value={newDocumentName}
            onChange={(e) => setNewDocumentName(e.target.value)}
          />
        ) : (
          <SearchTagSelect
            items={documents}
            selectedItem={selectedDocument}
            onItemSelected={onDocumentSelected}
            selectText={_t("Select document")}
            searchText={_t("Search document")}
          />
        )}
      </div>
      <div className="mt-2">
        {saveNew && (
          <Tags
            tags={documentTags}
            selectedTags={selectedDocumentTags}
            onTagSelected={onDocumentTagSelected}
            onTagDeselected={onDocumentTagDeselected}
          />
        )}
      </div>
    </div>
  );
};

export default SaveDocument;
