import * as React from "react";
import { useEffect, useState } from "react";
import { _t } from "../../../utils/Translator";
import type { CaseItem } from "../case/Case";
import Analysis, { AnalysisItem } from "../analysis/Analysis";
import { MainPages } from "../main/Main";
import Error from "../error/Error";
import type { WorkflowItem } from "../workflow/Workflow";

interface OpenAnalysisPageProps {
  selectedCase: CaseItem | null;
  selectedAnalysis: AnalysisItem | null;
  onCaseSelected: (c: CaseItem | null) => void;
  onAnalysisSelected: (a: AnalysisItem | null) => void;
  workflows: WorkflowItem[];
  goToPage: (page: MainPages) => void;
}

const OpenAnalysisPage: React.FC<OpenAnalysisPageProps> = (props: OpenAnalysisPageProps) => {
  const {
    selectedCase,
    selectedAnalysis,
    onCaseSelected,
    onAnalysisSelected,
    goToPage,
  } = props;
  const [error, setError] = useState<string>("");

  useEffect(() => {
    if (selectedCase?.id && selectedAnalysis?.caseId && selectedAnalysis.caseId !== selectedCase.id) {
      onAnalysisSelected(null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedCase?.id]);

  const onOpenAnalysis = async () => {
    if (!selectedAnalysis?.id) {
      setError("Please select an analysis.");
      return;
    }
    if (!selectedCase?.id && selectedAnalysis?.caseId) {
      onCaseSelected({ id: selectedAnalysis.caseId, name: `Case #${selectedAnalysis.caseId}` });
    }
    goToPage(MainPages.AnalysisPage);
  };

  const onNewAnalysis = () => {
    onAnalysisSelected(null);
    goToPage(MainPages.AnalysisPage);
  };

  const getCancelButton = () => {
    return (
      <button
        title="Return"
        type="button"
        className="btn btn-default"
        onClick={() => goToPage(MainPages.MainPage)}
      >
        <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
      </button>
    );
  };

  const getOpenAnalysisButton = () => {
    return (
      <button title="Open" type="button" className="btn btn-primary" onClick={onOpenAnalysis}>
        {_t("Open")}
      </button>
    );
  };

  const getNewAnalysisButton = () => {
    return (
      <button title="New" type="button" className="btn btn-light" onClick={onNewAnalysis}>
        {_t("New")}
      </button>
    );
  };

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{_t("Select analysis")}</span>
      </div>
      <Error error={error} setError={setError} />
      <Analysis
        selectedAnalysis={selectedAnalysis}
        onAnalysisSelected={onAnalysisSelected}
        selectedCaseId={selectedCase?.id}
      />
      <div className="d-flex justify-content-end gap-2 page-button-container">
        <div>{getNewAnalysisButton()}</div>
        {selectedAnalysis && <div>{getOpenAnalysisButton()}</div>}
      </div>
    </div>
  );
};

export default OpenAnalysisPage;
