import * as React from "react";
import { _t } from "../../../utils/Translator";
import SearchSelect from "../searchselect/SearchSelect";

export interface DocSnippetItem {
  name: string;
  id: number;
}

export interface DocSnippetProps {
  docSnippets: DocSnippetItem[];
  selectedDocSnippet: DocSnippetItem | null;
  onDocSnippetSelected: (t: DocSnippetItem | null) => void;
}

const DocSnippet: React.FC<DocSnippetProps> = (props: DocSnippetProps) => {
  const { docSnippets, selectedDocSnippet, onDocSnippetSelected } = props;

  return (
    <div>
      <SearchSelect
        items={docSnippets}
        selectedItem={selectedDocSnippet}
        onItemSelected={onDocSnippetSelected}
        selectText={_t("Select document snippet")}
        searchText={_t("Search document snippet")}
      />
    </div>
  );
};

export default DocSnippet;
