import * as React from "react";
import { sendHttpRequest, HttpVerb, ContentType } from "../../../utils/httpRequest";
import api from "../../api";
import { _t } from "../../../utils/Translator";
import { MainPages } from "../main/Main";
import DocSnippet, { DocSnippetItem } from "../doc_snippet/DocSnippet";
import { insertDocument } from "../../../utils/wordUtils";
import Error from "../error/Error";
import { useState } from "react";

interface OpenSnippetPageProps {
  docSnippets: DocSnippetItem[];
  selectedDocSnippet: DocSnippetItem | null;
  onDocSnippetSelected: (t: DocSnippetItem | null) => void;
  getConnectionToken: () => string;
  goToPage: (page: MainPages) => void;
}

const OpenSnippetPage: React.FC<OpenSnippetPageProps> = (props: OpenSnippetPageProps) => {
  const { docSnippets, selectedDocSnippet, onDocSnippetSelected, getConnectionToken, goToPage } = props;
  const [error, setError] = useState<string>("");

  const openDocSnippet = async (snippet: DocSnippetItem | null) => {
    let response = null;
    try {
      const request = sendHttpRequest(
        HttpVerb.POST,
        api.baseURL + api.openDocSnippet,
        ContentType.Json,
        getConnectionToken(),
        { snippet_id: snippet && snippet.id },
        true
      );
      response = JSON.parse(await request.promise);
    } catch (error) {
      setError(String(error));
    }
    return response;
  };

  const onOpenDocSnippet = async () => {
    const response = await openDocSnippet(selectedDocSnippet);
    if (response.result.success) {
      await insertDocument(response.result.data.datas);
      goToPage(MainPages.MainPage);
    } else {
      setError(response.result.error);
    }
  };

  const getOpenDocSnippetButton = () => {
    return (
      <button title="Confirm" type="button" className="btn btn-primary" onClick={onOpenDocSnippet}>
        {_t("Confirm")}
      </button>
    );
  };

  const getCancelButton = () => {
    return (
      <button title="Return" type="button" className="btn btn-default" onClick={() => goToPage(MainPages.MainPage)}>
        <i className="fa fa-arrow-left text-primary" aria-hidden="true"></i>
      </button>
    );
  };

  return (
    <div>
      <div className="d-flex align-items-center gap-2 page-header">
        {getCancelButton()}
        <span className="page-title">{_t("Select snippet")}</span>
      </div>
      <Error error={error} setError={setError} />
      <DocSnippet
        docSnippets={docSnippets}
        selectedDocSnippet={selectedDocSnippet}
        onDocSnippetSelected={onDocSnippetSelected}
      />
      <div className="d-flex justify-content-end page-button-container">
        {selectedDocSnippet && <span>{getOpenDocSnippetButton()}</span>}
      </div>
    </div>
  );
};

export default OpenSnippetPage;
