import * as React from "react";

export interface SearchItem {
  name: string;
  id: number;
}

export interface LazySearchSelectProps {
  items: SearchItem[];
  selectedItem: SearchItem | null;
  onItemSelected: (i: SearchItem | null) => void;
  selectText: string;
  searchText: string;
  onSearch?: (query: string) => void;
}

export interface LazySearchSelectState {
  searchInput: string;
  isFocused: boolean;
}

export default class LazySearchSelect<T extends LazySearchSelectProps> extends React.Component<T, LazySearchSelectState> {
  constructor(props) {
    super(props);
    this.state = {
      searchInput: props.selectedItem?.name ?? "",
      isFocused: false,
    };
  }

  componentDidUpdate(prevProps: T) {
    const prevSelected = prevProps.selectedItem;
    const nextSelected = this.props.selectedItem;
    const prevId = prevSelected?.id ?? null;
    const nextId = nextSelected?.id ?? null;
    const prevName = prevSelected?.name ?? "";
    const nextName = nextSelected?.name ?? "";
    if (prevId !== nextId || prevName !== nextName) {
      this.setState({ searchInput: nextName });
    }
  }

  filterItem = (item: SearchItem, searchInput: string) => {
    return item.name.toLowerCase().includes(searchInput);
  };

  filterItems = (items: SearchItem[], searchInput: string) => {
    let filteredItems = items.filter((item) => this.filterItem(item, searchInput));
    return filteredItems;
  };

  getItemsToShow = (items: SearchItem[]) => {
    let itemsToShow = [];
    const searchInputLower = this.state.searchInput.trim().toLowerCase();
    const sourceItems = Array.isArray(items) ? items : [];
    const filteredItems = searchInputLower ? this.filterItems(sourceItems, searchInputLower) : sourceItems;
    for (let i of filteredItems) {
      let id = i.id;
      itemsToShow.push(
        <li
          key={id}
          className="searchselect-item"
          onMouseDown={(e) => e.preventDefault()}
          onClick={() => {
            this.props.onItemSelected(i);
            this.setState({ searchInput: i.name, isFocused: false });
            if (this.props.onSearch) {
              this.props.onSearch("");
            }
          }}
        >
          {i.name}
        </li>
      );
    }
    return itemsToShow;
  };

  render() {
    const { items, searchText, selectedItem } = this.props;
    let itemsToShow = this.getItemsToShow(items);
    const showResults = this.state.isFocused;
    const hasInput = this.state.searchInput.trim().length > 0;
    return (
      <div className="searchselect-panel">
        <div className="searchselect-input-wrapper">
          <input
            className="form-control searchselect-input-field"
            type="text"
            value={this.state.searchInput}
            onFocus={() => this.setState({ isFocused: true })}
            onBlur={() => this.setState({ isFocused: false })}
            onChange={(e) => {
              const value = e.target.value;
              this.setState({ searchInput: value });
              if (this.props.onSearch) {
                this.props.onSearch(value);
              }
            }}
            placeholder={searchText}
          />
          {hasInput && (
            <button
              type="button"
              className="searchselect-clear-button"
              aria-label="Clear selection"
              title="Clear"
              onMouseDown={(e) => e.preventDefault()}
              onClick={() => {
                this.props.onItemSelected(null);
                this.setState({ searchInput: "", isFocused: true });
                if (this.props.onSearch) {
                  this.props.onSearch("");
                }
              }}
            >
              <i className="fa fa-times" aria-hidden="true"></i>
            </button>
          )}
        </div>
        {showResults && (itemsToShow.length > 0 ? (
          <ul className="searchselect-list">{itemsToShow}</ul>
        ) : (
          this.state.searchInput.trim().length > 0 && <div className="text-muted searchselect-empty">No results</div>
        ))}
      </div>
    );
  }
}
